set -e

# Pass any argument to use patch(1) instead of nextvi ex commands
if [ -n "$1" ]; then
    sed '1,/^=== PATCH2VI PATCH ===$/d' "$0" | patch -p1 --merge=diff3
    exit $?
fi

# Path to nextvi (adjust as needed)
VI=${VI:-vi}

# Uncomment to enter interactive vi on patch failure
#DBG="|sc|vis 2:e $0:@Q:q!1"
# Uncomment to skip errors (. = silent nop)
#DBG="."
# Set QF=. to continue despite errors (errors are still printed)
#QF=.

# Verify that VI is nextvi
if ! $VI -? 2>&1 | grep -q 'Nextvi'; then
    echo "Error: $VI is not nextvi" >&2
    echo "Set VI environment variable to point to nextvi" >&2
    exit 1
fi

# Patch: ex.c
SEP="$(printf '\001')"
QF=${QF-"$(printf 'vis 2\\\001q! 1')"}
EXINIT="rcm:|sc! \\\\${SEP}|vis 3${SEP}%;f> 			fd < 0 \\\\|\\\\| rd \\\\? 'f' : 'r'\\\\);
	if \\\\(!\\\\(xvis & 4\\\\)\\\\)
		ex_print\\\\(msg, bar_ft\\\\)${SEP}??!${DBG:--5,+5p\\${SEP}p FAIL line 380\\${SEP}${QF}}${SEP};=
${SEP}+2a 	if (!rd && fd >= 0 && lbuf_len(xb) > 0) {
		int adv = 0;
		while (lbuf_len(xb) > adv+1 && xb->ln[adv][0] == '\\\\n')
			adv++;
		struct filetype lfts[] = {
			{FT(sh), \"^#!.*/(env[ \\\\t]*)?(sh|bash|zsh|dash)([ \\\\t]*.*)?\$\"},
			{FT(py), \"^#!.*/(env[ \\\\t]*)?python3?([ \\\\t]*.*)?\$\"}
		};
		char *pats[LEN(lfts)];
		for (int i = 0; i < LEN(lfts); i++)
			pats[i] = lfts[i].pat;
		rset *rs = rset_make(LEN(lfts), pats, 0);
		int hl = rset_find(rs, xb->ln[adv], NULL, REG_NEWLINE);
		if (hl >= 0)
			xb_ft = syn_setft(lfts[hl].ft);
		rset_free(rs);
	}
.
${SEP}vis 2${SEP}wq" $VI -e 'ex.c'

exit 0
